SELECT
    friend_id AS friendId,
    requester_id AS requesterId,
    receiver_id AS receiverId,
    status
FROM friends
WHERE (
        requester_id = #{userId}
    AND receiver_id = #{targetUserId}
)
OR (
        requester_id = #{targetUserId}
    AND receiver_id = #{userId}
)
FETCH FIRST 1 ROWS ONLY
